    url = f"{base_url}/api/v1/compare"
    headers = {
        "Accept": "application/json"
    }
    try:
        response = requests.get(url, headers=headers, timeout=30)
        assert response.status_code == 400, f"Expected status code 400 but got {response.status_code}"
